body:
input: 
```mlir
module attributes {circt.loweringOptions = "disallowLocalVariables"} {
  hw.module @Foo( %clock: i1, %opcode: i3) {
    %c-2_i3 = hw.constant -2 : i3
    %0 = comb.icmp eq %opcode, %c-2_i3 : i3
    sv.ifdef  "SYNTHESIS" {
    } else {
      sv.always posedge %clock {
        sv.if %0 {
          sv.error "Foo"
        }
      }
    }
    hw.output
  }
}
```
```verilog
module Foo(     // tmp2.mlir:2:3
  input       clock,
  input [2:0] opcode);

  `ifndef SYNTHESIS     // tmp2.mlir:5:5
  wire _GEN = opcode == 3'h6;   // tmp2.mlir:3:15, :4:10
    always @(posedge clock) begin       // tmp2.mlir:7:7
      if (_GEN) // tmp2.mlir:8:9
        $error("Foo");  // tmp2.mlir:9:11
    end // always @(posedge)
  `endif
endmodule
```

`_GEN` should be inlined to if condition since it is used only once. If `sv.always` and `sv.ifdef` are reversed, `_GEN` is inlined so it seems https://github.com/llvm/circt/commit/28f3193971cabd88a82a21d4ce8154ebd16a44c7 exposed this problem.
